def _param(info, evalable=False):
    "JSON schema non-type metadata for a parameter"
    pschema = dict(description=info.docment or "")
    if info.default is not empty:
        if evalable:
            try: ast.literal_eval(repr(info.default))
            except: pschema["default"] = str(info.default)
            else: pschema["default"] = info.default
        else: pschema["default"] = info.default
    return pschema

