custom_types = {Path, bytes, Decimal, UUID}
_tmap = {int: "integer", float: "number", str: "string", bool: "boolean", list: "array", dict: "object"}
_nmap = {k.__name__: v for k, v in _tmap.items()}

def _type_str(t):
    "JSON Schema type name for a type or string annotation"
    if isinstance(t, str): return _nmap.get(t, "object")
    base = _tmap.get(get_origin(t) or t, _nmap.get(getattr(t, '__name__', ''), "object"))
    if (args := get_args(t)): return f"{base}[{', '.join(_type_str(a) for a in args if a is not Ellipsis)}]"
    return base

